const body = $input.first().json.body || $input.first().json;
const id = body.id;
const tenantId = body.tenantId;
const nom = body.nom;
const sujet = body.sujet;
const contenuHtml = body.contenuHtml;
const contenuText = body.contenuText;
const variables = body.variables;
const categorie = body.categorie;

function esc(v) {
  return v == null ? 'NULL' : "'" + String(v).replace(/'/g, "''") + "'";
}

const updates = [];
if (nom !== undefined) updates.push(`nom = ${esc(nom)}`);
if (sujet !== undefined) updates.push(`sujet = ${esc(sujet)}`);
if (contenuHtml !== undefined) updates.push(`contenu_html = ${esc(contenuHtml)}`);
if (contenuText !== undefined) updates.push(`contenu_text = ${esc(contenuText)}`);
if (variables !== undefined) {
  const variablesArray = Array.isArray(variables) ? variables.map(v => esc(v)).join(',') : '';
  const variablesSql = variablesArray ? `ARRAY[${variablesArray}]` : `ARRAY[]::text[]`;
  updates.push(`variables = ${variablesSql}`);
}
if (categorie !== undefined) updates.push(`categorie = ${esc(categorie)}`);

updates.push(`updated_at = NOW()`);

const sql = `UPDATE email_templates SET ${updates.join(', ')} WHERE id = ${esc(id)}::uuid AND tenant_id = ${esc(tenantId)} RETURNING id, tenant_id AS "tenantId", nom, sujet, contenu_html AS "contenuHtml", contenu_text AS "contenuText", variables, categorie, thumbnail, created_at AS "createdAt", updated_at AS "updatedAt"`;

return { sql };

const rows = $input.first().json;
const template = Array.isArray(rows) && rows.length > 0 ? rows[0] : {};
const formatted = {
  template: template
};
return formatted;
